  1 | /**
  2 |  * Seed-surface framework — generic manual-entry surfaces backed by their own
  3 |  * SQLite table, created lazily via a self-healing migration.
  4 |  *
  5 |  * Each surface is identified by a slug (e.g. "podcast", "video") and has:
  6 |  *  - a dedicated table `seed_<slug>` (id, title, status, category, body, url,
  7 |  *    meta JSON, created_at, updated_at)
  8 |  *  - CRUD via listSeed/createSeed
  9 |  *  - a seed of realistic sample rows on first access
 10 |  *
 11 |  * This lets the 12 no-scrape-source surfaces ship now as manual-entry apps
 12 |  * with adapter hooks left for future ingest.
 13 |  */
 14 | import { db, now, uid } from "@/lib/db";
 15 | 
 16 | export interface SeedSurfaceConfig {
 17 |   slug: string;
 18 |   label: string;
 19 |   icon?: string;
 20 |   statuses: string[];
 21 |   categories: string[];
 22 |   seed: { title: string; status: string; category: string; body: string; url?: string; meta?: Record<string, unknown> }[];
 23 | }
 24 | 
 25 | export interface SeedRow {
 26 |   id: string;
 27 |   title: string;
 28 |   status: string;
 29 |   category: string;
 30 |   body: string;
 31 |   url: string;
 32 |   meta: Record<string, unknown>;
 33 |   created_at: number;
 34 |   updated_at: number;
 35 | }
 36 | 
 37 | const TABLE = (slug: string) => `seed_${slug.replace(/[^a-z0-9]/gi, "_").toLowerCase()}`;
 38 | const seeded = new Set<string>();
 39 | 
 40 | /** Lazily create the surface table + seed it once. */
 41 | export function ensureSeedSurface(cfg: SeedSurfaceConfig): void {
 42 |   const table = TABLE(cfg.slug);
 43 |   if (seeded.has(table)) return;
 44 |   db.exec(`
 45 |     CREATE TABLE IF NOT EXISTS ${table} (
 46 |       id TEXT PRIMARY KEY,
 47 |       title TEXT NOT NULL,
 48 |       status TEXT NOT NULL DEFAULT 'draft',
 49 |       category TEXT NOT NULL DEFAULT 'general',
 50 |       body TEXT NOT NULL DEFAULT '',
 51 |       url TEXT NOT NULL DEFAULT '',
 52 |       meta TEXT NOT NULL DEFAULT '{}',
 53 |       created_at INTEGER NOT NULL,
 54 |       updated_at INTEGER NOT NULL
 55 |     );
 56 |     CREATE INDEX IF NOT EXISTS idx_${table}_status ON ${table}(status);
 57 |     CREATE INDEX IF NOT EXISTS idx_${table}_cat ON ${table}(category);
 58 |   `);
 59 |   // seed once if empty
 60 |   const count = (db.prepare(`SELECT COUNT(*) c FROM ${table}`).get() as { c: number }).c;
 61 |   if (count === 0 && cfg.seed.length > 0) {
 62 |     const stmt = db.prepare(
 63 |       `INSERT INTO ${table} (id, title, status, category, body, url, meta, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)`,
 64 |     );
 65 |     const t = now();
 66 |     for (const s of cfg.seed) {
 67 |       stmt.run(uid(cfg.slug), s.title, s.status, s.category, s.body, s.url || "", JSON.stringify(s.meta || {}), t, t);
 68 |     }
 69 |   }
 70 |   seeded.add(table);
 71 | }
 72 | 
 73 | /** List rows for a surface. */
 74 | export function listSeed(slug: string, status?: string, limit = 100): SeedRow[] {
 75 |   const table = TABLE(slug);
 76 |   const rows = status
 77 |     ? db.prepare(`SELECT * FROM ${table} WHERE status = ? ORDER BY updated_at DESC LIMIT ?`).all(status, limit)
 78 |     : db.prepare(`SELECT * FROM ${table} ORDER BY updated_at DESC LIMIT ?`).all(limit);
 79 |   return (rows as Record<string, unknown>[]).map((r) => ({
 80 |     id: String(r.id),
 81 |     title: String(r.title),
 82 |     status: String(r.status),
 83 |     category: String(r.category),
 84 |     body: String(r.body || ""),
 85 |     url: String(r.url || ""),
 86 |     meta: (() => { try { return JSON.parse(String(r.meta || "{}")); } catch { return {}; } })(),
 87 |     created_at: Number(r.created_at) || 0,
 88 |     updated_at: Number(r.updated_at) || 0,
 89 |   }));
 90 | }
