 92 | /** Create a row for a surface. */
 93 | export function createSeed(slug: string, input: { title: string; status?: string; category?: string; body?: string; url?: string; meta?: Record<string, unknown> }): string {
 94 |   const table = TABLE(slug);
 95 |   const id = uid(slug);
 96 |   const t = now();
 97 |   db.prepare(
 98 |     `INSERT INTO ${table} (id, title, status, category, body, url, meta, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)`,
 99 |   ).run(id, input.title, input.status || "draft", input.category || "general", input.body || "", input.url || "", JSON.stringify(input.meta || {}), t, t);
100 |   return id;
101 | }

