#!/usr/bin/env tsx
/**
 * add-feature — Marketing Hub feature-addition scaffolder.
 *
 * The hub ships a fully data-driven "seed surface" pattern: a generic backend
 * (`src/lib/seed-surface.ts`) + generic API (`src/app/api/seed/[slug]/route.ts`)
 * serve ANY surface defined by a config entry. Adding a new section therefore
 * only requires three mechanical edits:
 *
 *   1. a config entry in `src/lib/seed-surfaces.ts`
 *   2. a thin page at `src/app/<slug>/page.tsx`
 *   3. a nav entry in `src/components/Sidebar.tsx`
 *
 * This script performs all three, idempotently, so you can push the build to
 * its limit by adding sections as fast as you can name them.
 *
 * Usage (single):
 *   tsx scripts/add-feature.ts --slug newsletter --label Newsletter \
 *     --icon Newspaper --statuses "draft,scheduled,sent,archived" \
 *     --categories "daily,weekly,promo,digest"
 *
 * Usage (batch — push to the limit):
 *   tsx scripts/add-feature.ts --batch scripts/features-batch.json
 *
 * Flags:
 *   --slug        kebab-case unique id (required for single mode)
 *   --label       human label shown in UI + nav
 *   --icon        lucide-react icon name (e.g. Newspaper)
 *   --group       sidebar group to join (default: "Channels")
 *   --statuses    comma list of pipeline statuses
 *   --categories  comma list of categories
 *   --dry-run     print the edits without writing
 *   --batch       path to a JSON array of feature specs
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
import { join } from "node:path";

const ROOT = process.cwd();
const SEED_SURFACES = join(ROOT, "src/lib/seed-surfaces.ts");
const SIDEBAR = join(ROOT, "src/components/Sidebar.tsx");
const APP_DIR = join(ROOT, "src/app");

interface SeedRow {
  title: string;
  status: string;
  category: string;
  body: string;
  url?: string;
  meta?: Record<string, unknown>;
}

interface FeatureSpec {
  slug: string;
  label: string;
  icon: string;
  group?: string;
  statuses: string[];
  categories: string[];
  seed?: SeedRow[];
}

// ── arg parsing ──────────────────────────────────────────────────────────────
function parseArgs(argv: string[]): Record<string, string> {
  const out: Record<string, string> = {};
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    if (a.startsWith("--")) {
      const key = a.slice(2);
      const val = argv[i + 1] && !argv[i + 1].startsWith("--") ? argv[++i] : "true";
      out[key] = val;
    }
  }
  return out;
}

function splitList(v: string | undefined): string[] {
  if (!v) return [];
  return v.split(",").map((s) => s.trim()).filter(Boolean);
}

function specFromArgs(args: Record<string, string>): FeatureSpec {
  const slug = (args.slug || "").trim();
  const label = (args.label || "").trim();
  const icon = (args.icon || "").trim();
  if (!slug || !label || !icon) {
    throw new Error("Single mode requires --slug, --label and --icon");
  }
  const statuses = splitList(args.statuses);
  const categories = splitList(args.categories);
  if (statuses.length === 0) statuses.push("draft", "active", "archived");
  if (categories.length === 0) categories.push("general");
  return {
    slug,
    label,
    icon,
    group: args.group || "Channels",
    statuses,
    categories,
  };
}

// ── validation ──────────────────────────────────────────────────────────────
function assertSlug(slug: string) {
  if (!/^[a-z0-9]+(?:-[a-z0-9]+)*$/.test(slug)) {
    throw new Error(`Invalid slug "${slug}" — use kebab-case lowercase (e.g. "web-push")`);
  }
}

function slugInRegistry(content: string, slug: string): boolean {
  return new RegExp(`slug:\\s*["']${slug}["']`).test(content);
}

function hrefInSidebar(content: string, slug: string): boolean {
  return new RegExp(`href:\\s*["']/${slug}["']`).test(content);
}

function iconImported(content: string, icon: string): boolean {
  return new RegExp(`\\b${icon}\\b`).test(content);
}

// ── generators ──────────────────────────────────────────────────────────────
function defaultSeed(spec: FeatureSpec): SeedRow[] {
  if (spec.seed && spec.seed.length) return spec.seed;
  const s0 = spec.statuses[0];
  const s1 = spec.statuses[1] || s0;
  const c0 = spec.categories[0];
  const c1 = spec.categories[1] || c0;
  const low = spec.label.toLowerCase();
  return [
    { title: `${spec.label} — pilot entry`, status: s0, category: c0, body: `First ${low} item. Edit or add more above.`, meta: {} },
    { title: `${spec.label} — example B`, status: s1, category: c1, body: `Second ${low} item for demonstration.`, meta: {} },
  ];
}

function registryEntry(spec: FeatureSpec): string {
  const rows = defaultSeed(spec)
    .map((r) => {
      const meta = r.meta && Object.keys(r.meta).length ? `, meta: ${JSON.stringify(r.meta)}` : "";
      const url = r.url ? `, url: "${r.url}"` : "";
      return `      { title: ${JSON.stringify(r.title)}, status: ${JSON.stringify(r.status)}, category: ${JSON.stringify(r.category)}, body: ${JSON.stringify(r.body)}${url}${meta} }`;
    })
    .join(",\n");
  return `  {
    slug: ${JSON.stringify(spec.slug)},
    label: ${JSON.stringify(spec.label)},
    statuses: ${JSON.stringify(spec.statuses)},
    categories: ${JSON.stringify(spec.categories)},
    seed: [
${rows}
    ],
  },`;
}

function pageFile(spec: FeatureSpec): string {
  return `"use client";
import { ${spec.icon} } from "lucide-react";
import { SeedSurface } from "@/components/seed-surface/SeedSurface";

export default function Page() {
  return <SeedSurface slug="${spec.slug}" label="${spec.label}" icon={<${spec.icon} className="w-7 h-7 text-indigo-500" />} />;
}
`;
}

// ── mutators ────────────────────────────────────────────────────────────────
function addToRegistry(content: string, spec: FeatureSpec): string {
  if (slugInRegistry(content, spec.slug)) return content;
  const idx = content.lastIndexOf("];");
  if (idx === -1) throw new Error("Could not find array close in seed-surfaces.ts");
  return content.slice(0, idx) + registryEntry(spec) + "\n" + content.slice(idx);
}

function addIconImport(content: string, icon: string): string {
  if (iconImported(content, icon)) return content;
  return content.replace(
    /} from "lucide-react";/,
    `  ${icon},\n} from "lucide-react";`,
  );
}

function addToSidebar(content: string, spec: FeatureSpec): string {
  if (hrefInSidebar(content, spec.slug)) return content;
  const group = spec.group || "Channels";
  const groupIdx = content.indexOf(`group: "${group}"`);
  if (groupIdx === -1) {
    throw new Error(`Sidebar group "${group}" not found — add the nav entry manually`);
  }
  const closeIdx = content.indexOf("  ]},", groupIdx);
  if (closeIdx === -1) throw new Error(`Could not find group close for "${group}"`);
  const line = `    { href: "/${spec.slug}", label: ${JSON.stringify(spec.label)}, icon: ${spec.icon}, badge: "NEW" },\n`;
  let next = content.slice(0, closeIdx) + line + content.slice(closeIdx);
  next = addIconImport(next, spec.icon);
  return next;
}

// ── driver ──────────────────────────────────────────────────────────────────
function applyFeature(spec: FeatureSpec, dryRun: boolean): string[] {
  assertSlug(spec.slug);
  const log: string[] = [];

  // 1. page
  const pagePath = join(APP_DIR, spec.slug, "page.tsx");
  if (existsSync(pagePath)) {
    log.push(`• page src/app/${spec.slug}/page.tsx — already exists, skipped`);
  } else {
    if (!dryRun) {
      mkdirSync(join(APP_DIR, spec.slug), { recursive: true });
      writeFileSync(pagePath, pageFile(spec));
    }
    log.push(`• page src/app/${spec.slug}/page.tsx — ${dryRun ? "would create" : "created"}`);
  }

  // 2. registry
  let reg = readFileSync(SEED_SURFACES, "utf8");
  const before = reg;
  reg = addToRegistry(reg, spec);
  if (reg === before) {
    log.push(`• registry src/lib/seed-surfaces.ts — slug already present, skipped`);
  } else {
    if (!dryRun) writeFileSync(SEED_SURFACES, reg);
    log.push(`• registry src/lib/seed-surfaces.ts — ${dryRun ? "would append" : "appended"} entry`);
  }

  // 3. sidebar
  let sb = readFileSync(SIDEBAR, "utf8");
  const sbBefore = sb;
  sb = addToSidebar(sb, spec);
  if (sb === sbBefore) {
    log.push(`• nav src/components/Sidebar.tsx — entry already present, skipped`);
  } else {
    if (!dryRun) writeFileSync(SIDEBAR, sb);
    log.push(`• nav src/components/Sidebar.tsx — ${dryRun ? "would add" : "added"} "${spec.label}" to ${spec.group || "Channels"}`);
  }

  return log;
}

function main() {
  const args = parseArgs(process.argv.slice(2));
  const dryRun = args["dry-run"] === "true";

  let specs: FeatureSpec[] = [];
  if (args.batch) {
    const raw = JSON.parse(readFileSync(join(ROOT, args.batch), "utf8"));
    specs = raw.map((s: any) => ({
      slug: s.slug,
      label: s.label,
      icon: s.icon,
      group: s.group || "Channels",
      statuses: s.statuses || ["draft", "active", "archived"],
      categories: s.categories || ["general"],
      seed: s.seed,
    }));
  } else {
    specs = [specFromArgs(args)];
  }

  if (specs.length === 0) {
    console.error("No features to add. Use --slug/--label/--icon or --batch <file.json>.");
    process.exit(1);
  }

  console.log(`\n⚡ add-feature — ${dryRun ? "DRY RUN" : "APPLYING"} ${specs.length} feature(s)\n`);
  let total = 0;
  for (const spec of specs) {
    try {
      const lines = applyFeature(spec, dryRun);
      total += lines.length;
      console.log(`▸ ${spec.slug} (${spec.label})`);
      lines.forEach((l) => console.log("   " + l));
    } catch (e) {
      console.error(`   ✗ ${spec.slug}: ${(e as Error).message}`);
    }
    console.log("");
  }
  console.log(`Done. ${total} edit(s) ${dryRun ? "planned" : "applied"}.\n`);
}

main();

